class Solution:
    def alternateDigitSum(self, n: int) -> int:
        n_str = str(n)
        total = 0
        for i, digit in enumerate(n_str):
            value = int(digit)
            if i % 2 == 0:
                total += value
            else:
                total -= value
        return total

